3	public actor UsagePoller {
4	    public let connectors: [any UsageConnector]
5	    public let interval: Duration
6	    public let fileManager: UsagesFileManager
7	    private let logger: FileLogger
8	    private let refreshState: RefreshState?
9	
10	    private var pollingTask: Task<Void, Never>?
11	
12	    public init(
13	        connectors: [any UsageConnector],
14	        interval: Duration = .seconds(180),
15	        fileManager: UsagesFileManager = UsagesFileManager.shared,
16	        logger: FileLogger = Loggers.app,
17	        refreshState: RefreshState? = nil
18	    ) {
19	        self.connectors = connectors
20	        self.interval = interval
21	        self.fileManager = fileManager
22	        self.logger = logger
23	        self.refreshState = refreshState
24	    }
25	
26	    public func start() {
27	        guard pollingTask == nil else {
28	            logger.log(.warning, "Poller already running")
29	            return
30	        }
31	        logger.log(.info, "Starting poller with interval \(interval)")
32	        pollingTask = Task {
33	            while !Task.isCancelled {
34	                await self.pollOnce()
35	                // Sleep-based cadence: effective period = poll duration + interval.
36	                // This is intentional — avoids overlapping polls at the cost of slight drift.
37	                try? await Task.sleep(for: self.interval)
38	                guard !Task.isCancelled else { break }
39	            }
40	        }
41	    }
42	
43	    public func stop() {
44	        pollingTask?.cancel()
45	        pollingTask = nil
46	        logger.log(.info, "Poller stopped")
47	    }
48	
49	    public func pollOnce(now: Date = Date(), force: Bool = false) async {
50	        logger.log(.debug, "Poll tick — fetching from \(connectors.count) connector(s)\(force ? " (forced)" : "")")
51	
52	        let existingFile = await fileManager.read()
53	        let intervalSeconds = Double(interval.components.seconds)
54	        var skippedCount = 0
55	        let log = self.logger
56	
57	        let refreshState = self.refreshState
58	        let entries: [VendorUsageEntry] = await withTaskGroup(of: [VendorUsageEntry].self) { group in
59	            for connector in connectors {
60	                let account = connector.resolveActiveAccount()
61	                if !force,
62	                   let account,
63	                   let cached = existingFile.usages.first(where: { $0.vendor == connector.vendor && $0.account == account }),
64	                   let acquiredDate = cached.lastAcquiredOn?.date,
65	                   now.timeIntervalSince(acquiredDate) < intervalSeconds {
66	                    let age = Int(now.timeIntervalSince(acquiredDate))
67	                    logger.log(.debug, "Skipping \(connector.vendor)/\(account) — fresh (age \(age)s < \(Int(intervalSeconds))s)")
68	                    skippedCount += 1
69	                    continue
70	                }
71	                let refreshKey = account.map { AccountKey(vendor: connector.vendor, account: $0) }
72	                if let refreshKey {
73	                    await refreshState?.begin(refreshKey)
74	                }
75	                group.addTask {
76	                    let result: [VendorUsageEntry]
77	                    do {
78	                        result = try await connector.fetchUsages()
79	                    } catch {
80	                        log.log(.error, "Connector \(connector.vendor) threw: \(error)")
81	                        result = []
82	                    }
83	                    if let refreshKey {
84	                        await refreshState?.end(refreshKey)
85	                    }
86	                    return result
87	                }
88	            }
89	            var all: [VendorUsageEntry] = []
90	            for await batch in group {
91	                all.append(contentsOf: batch)
92	            }
93	            return all
94	        }
95	
96	        guard !entries.isEmpty else {
97	            if skippedCount == connectors.count {
98	                logger.log(.debug, "All \(connectors.count) connector(s) up-to-date — skipping file write")
99	            } else {
100	                logger.log(.warning, "No entries returned from any connector")
101	            }
102	            return
103	        }
104	
105	        await fileManager.update(with: entries)
106	        logger.log(.info, "Merged \(entries.count) entry/entries into usages file")
107	    }
108	}
